solution_code:
#include <iostream>

int main()
{
    char c {};
    std::cin >> c;

    if (c >= 'A' && c <= 'Z')
        std::cout << "uppercase\n";
    else if (c >= 'a' && c <= 'z')
        std::cout << "lowercase\n";
    else if (c >= '0' && c <= '9')
        std::cout << "digit\n";
    else
        std::cout << "other\n";

    return 0;
}

